#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  //Background
  ret = vec3(0.8627, 0.6157, 0.9922);

  float row_spacing = .65;

  //uAspect corr and global scaling
  vUv *= 3.5;
  q31 *= 0.35;
  q32 *= 0.35;

  //uAspect corr and global scaling
  vec2 aspect_texsize = vec2(1, uTexSize.y/uTexSize.x);
  vUv = (vUv-0.5)*aspect_texsize+0.5;

  //DeepSeek - Dynamic Row Count Aspect Ratio Calculation
  float aspect_ratio = uTexSize.x / uTexSize.y;
  int row_count = 5; // Default for 4:3 and 1:1

  // Adjust row count for extreme uAspect ratios
  if (aspect_ratio > 1.5) { // Very wide (e.g., 16:9)
    row_count = 3;
  }
  else if (aspect_ratio < 0.75) { // Very tall (e.g., 9:16)
    row_count = 8;
  }

  for (int row=1; row<=row_count; row++) {
    j = q31;
    uvi = vUv+vec2((q5*(row*2.5))/5 + q6*(row*q8), j+1 - row*row_spacing);
    ry = (uvi.y);
    tmp = mix(texture(Abbie_Normal,uvi), texture(Abbie_YAY,uvi), j>0.0001)*(ry<1)*(ry>0);
    ret = mix(ret, tmp, lum(tmp)>0);

    j = q32;
    uvi = vUv+vec2((q5*(row*2.5))/5 + q7*(row*q9), j+.55 - row*row_spacing);
    ry = (uvi.y);
    tmp = mix(texture(Abbie_Normal,uvi), texture(Abbie_YAY,uvi), j>0.0001)*(ry<1)*(ry>0);
    ret = mix(ret, tmp, lum(tmp)>0);
  }

  fragColor = ret;
}
